# Example: exponential backoff with circuit breaker for API resilience
import anthropic, time, random
from dataclasses import dataclass, field

@dataclass
class CircuitBreaker:
    failure_threshold: int = 5
    reset_timeout: float = 60.0
    _failures: int = field(default=0, repr=False)
    _last_failure_time: float = field(default=0.0, repr=False)
    _open: bool = field(default=False, repr=False)

    def call_permitted(self) -> bool:
        if not self._open:
            return True
        if time.monotonic() - self._last_failure_time > self.reset_timeout:
            self._open = False
            self._failures = 0
            return True
        return False

    def record_failure(self):
        self._failures += 1
        self._last_failure_time = time.monotonic()
        if self._failures >= self.failure_threshold:
            self._open = True

    def record_success(self):
        self._failures = 0
        self._open = False

_cb = CircuitBreaker()
client = anthropic.Anthropic()

def safe_complete(prompt: str, max_retries: int = 3) -> str | None:
    if not _cb.call_permitted():
        return None  # Circuit open — use fallback logic

    for attempt in range(max_retries):
        try:
            resp = client.messages.create(
                model="claude-opus-4-8",
                max_tokens=512,
                messages=[{"role": "user", "content": prompt}],
            )
            _cb.record_success()
            return resp.content[0].text
        except anthropic.APIStatusError as e:
            if e.status_code in (429, 529):  # Rate limit / overload
                wait = (2 ** attempt) + random.uniform(0, 1)
                time.sleep(wait)
            elif e.status_code >= 500:
                _cb.record_failure()
                raise
            else:
                raise  # 4xx client errors — don't retry
    return None
